!function(){"use strict";const e={"flat spatial distance":"The -dt<sup>2</sup> term adds time, and the (dx - v<sub>s</sub> f(r<sub>s</sub>)dt)<sup>2</sup> term replaces ordinary dx with dx minus a position-dependent x-coordinate shift between time slices.","Euclidean vs spacetime":"The warp metric is a spacetime metric, so dt matters as much as dx, dy, and dz.","flat spacetime baseline":"Flat spacetime adds time to the Euclidean-looking spatial pieces: -dt<sup>2</sup> + dx<sup>2</sup> + dy<sup>2</sup> + dz<sup>2</sup>.","the warp modification":"The structural change is inside the x term: ordinary dx becomes dx - v<sub>s</sub> f(r<sub>s</sub>)dt.","bubble speed v_s":"v<sub>s</sub> says how fast the bubble moves in the coordinate description, not how fast the ship moves locally.","shape function f(r_s)":"f(r<sub>s</sub>) shapes the bubble: 1 inside, 0 outside, and changing through the wall.","distance from ship r_s":"r<sub>s</sub> is the distance from the bubble center; it tells f where you are relative to the ship.","theta is derived, not inserted":"&theta; is computed from the metric. It is a diagnostic, not an extra ingredient in ds<sup>2</sup>.","meaning of theta":"Here the metric has introduced time through -dt<sup>2</sup>, then changed the x-distance element with the warp term (dx - v<sub>s</sub> f(r<sub>s</sub>)dt)<sup>2</sup>."},s={"field equations":"Matter and energy tell spacetime how to curve; curved spacetime tells matter how to move. With the required T<sub>&mu;&nu;</sub>, the metric can describe a bubble whose coordinate speed v<sub>s</sub> exceeds c, without making the ship locally outrun light.","metric as a solution":"The Alcubierre metric is a solution if the curvature it describes has a corresponding T<sub>&mu;&nu;</sub> source.","10c bubble source":"A 10c v<sub>s</sub> is a coordinate bubble speed. The equations ask what T<sub>&mu;&nu;</sub> would be needed to produce that geometry.","metric first":"The Alcubierre move is metric first, source second: choose the geometry, then calculate what it demands.","stress-energy tensor":"T<sub>&mu;&nu;</sub> contains energy density, momentum flow, pressure, and stress — the stuff that sources curvature.","exotic requirement":"The required T<sub>&mu;&nu;</sub> includes negative energy density, especially in the bubble wall.","superluminal v_s":"v<sub>s</sub> can be greater than c as a coordinate speed of the bubble; local motion still respects c.","carried by the bubble":"The ship rides inside a local region of spacetime carried by the bubble geometry.",geodesics:"In general relativity, freely falling matter follows geodesics. The ship can follow a geodesic inside the locally calm bubble interior while the bubble geometry changes the relation to far-away space."},t={"why special":"Core idea: the metric describes a moving bubble; v<sub>s</sub> is its coordinate speed.","shape function":"f(r<sub>s</sub>) is the bubble profile: interior, wall, and exterior.","wall structure":"The wall matters because f(r<sub>s</sub>) changes there, so curvature and source structure concentrate there.","theta meaning":"&theta; visualizes expansion or contraction of nearby spatial volume elements.","superluminal coordinate speed":"v<sub>s</sub> can exceed c as a coordinate speed while local motion still respects c.","einstein equations":"Einstein's equations connect the chosen geometry to the required T<sub>&mu;&nu;</sub>.","tensor field":"T<sub>&mu;&nu;</sub>(t,x,y,z) means the source is assigned point-by-point over spacetime.","physical catch":"The catch is not the algebra; it is the exotic stress-energy the source requires.","ship carried along":"The ship rides inside a locally calm region and can follow a geodesic.","big caveat":"Mathematical consistency is not the same as known buildability."};function i(e){const s={index:0,score:0,answered:!1,misses:[]};const t={progress:document.querySelector(e.progress),score:document.querySelector(e.score),focus:document.querySelector(e.focus),question:document.querySelector(e.question),answers:document.querySelector(e.answers),feedback:document.querySelector(e.feedback),next:document.querySelector(e.next),restart:document.querySelector(e.restart),caption:document.querySelector(e.caption)};function i(){const i=s.index>=e.questions.length;if(t.answers.innerHTML="",t.feedback.textContent="",s.answered=!1,t.score.textContent=`Score ${s.score}`,i)return t.progress.textContent="Complete",t.focus.innerHTML=e.completeFocus,t.question.textContent=`You scored ${s.score} / ${e.questions.length}.`,t.feedback.innerHTML=!1===e.showVerdict?"":s.score===e.questions.length?e.verdicts.perfect:s.score>=Math.ceil(.75*e.questions.length)?e.verdicts.strong:s.score>=Math.ceil(.45*e.questions.length)?e.verdicts.partial:e.verdicts.early,t.next.textContent="Done",t.next.disabled=!0,void s.misses.forEach(s=>{const i=e.questions[s],a=document.createElement("article");a.className="missed-card",a.innerHTML=`\n            <strong>${i.question}</strong>\n            <span>Answer: ${i.choices[i.answer]}</span>\n            <p>${i.feedback}</p>\n          `,t.answers.appendChild(a)});const a=e.questions[s.index];var n,o;t.progress.textContent=`Question ${s.index+1} / ${e.questions.length}`,t.focus.innerHTML=`Focus: ${n=a.focus,n.replaceAll("v_s","v<sub>s</sub>").replaceAll("r_s","r<sub>s</sub>").replaceAll("theta","&theta;")}`,t.question.innerHTML=a.question,t.next.textContent="Next question",t.next.disabled=!0,o=a,t.caption&&(t.caption.innerHTML=e.captions[o.focus]||e.defaultCaption),a.choices.forEach((i,a)=>{const n=document.createElement("button");n.type="button",n.innerHTML=i,n.addEventListener("click",()=>function(i){if(s.answered)return;const a=e.questions[s.index],n=i===a.answer;s.answered=!0,n?(s.score+=1,t.feedback.innerHTML=a.feedback):(s.misses.push(s.index),t.feedback.innerHTML=`Not quite. ${a.feedback}`);t.score.textContent=`Score ${s.score}`,t.answers.querySelectorAll("button").forEach((e,s)=>{e.disabled=!0,e.classList.toggle("correct",s===a.answer),e.classList.toggle("incorrect",s===i&&!n)}),t.next.disabled=!1}(a)),t.answers.appendChild(n)})}t.next.addEventListener("click",()=>{s.answered&&(s.index+=1,i())}),t.restart.addEventListener("click",()=>{s.index=0,s.score=0,s.answered=!1,s.misses=[],i()}),i()}i({questions:[{focus:"flat spatial distance",question:"What does the Euclidean metric measure?",choices:["A position-dependent spacetime shift around a ship","Distance through ordinary flat space","How fast time passes near a black hole","The amount of negative energy in the wall"],answer:1,feedback:"Right. Euclidean geometry is the familiar ruler-and-grid idea: ds<sup>2</sup> = dx<sup>2</sup> + dy<sup>2</sup> + dz<sup>2</sup>."},{focus:"flat spacetime baseline",question:"Before adding the warp term, flat spacetime looks closest to which expression?",choices:["ds<sup>2</sup> = dx<sup>2</sup> + dy<sup>2</sup> + dz<sup>2</sup>","&theta; = v<sub>s</sub> (x/r<sub>s</sub>) df/dr<sub>s</sub>","ds<sup>2</sup> = -dt<sup>2</sup> + dx<sup>2</sup> + dy<sup>2</sup> + dz<sup>2</sup>","f(r<sub>s</sub>) = 0 everywhere"],answer:2,feedback:"Good. The -dt<sup>2</sup> part is the relativity move: time is included, but with the opposite sign from space."},{focus:"the warp modification",question:"In the Alcubierre metric, which part is the actual warp modification?",choices:["dy<sup>2</sup> + dz<sup>2</sup>","The equals sign","Only -dt<sup>2</sup>","dx - v<sub>s</sub> f(r<sub>s</sub>)dt"],answer:3,feedback:"Yes. The x direction is modified by subtracting v<sub>s</sub> f(r<sub>s</sub>)dt, a position-dependent x-coordinate shift between time slices."},{focus:"bubble speed v_s",question:"What does v<sub>s</sub> represent here?",choices:["A universal speed limit inside the equation","The ship's local speed through nearby space","The coordinate speed of the warp bubble","The radius of the bubble wall"],answer:2,feedback:"Right. v<sub>s</sub> is the bubble's coordinate speed. The ship can still be locally at everyday speed relative to nearby space."},{focus:"shape function f(r_s)",question:"What does f(r<sub>s</sub>) control?",choices:["The value of the speed of light","Where the warp effect is switched on or off","The number of spatial dimensions","Whether time exists"],answer:1,feedback:"Exactly. f(r<sub>s</sub>) is near 1 inside the bubble, near 0 outside, and changes through the wall."},{focus:"distance from ship r_s",question:"What is r<sub>s</sub>?",choices:["The ship's fuel supply","The energy density","Distance from the ship or bubble center","A second time coordinate"],answer:2,feedback:"Yes. r<sub>s</sub> is radial distance from the bubble center, so f(r<sub>s</sub>) can change as you move outward."},{focus:"theta is derived, not inserted",question:"Where does &theta; appear in the warp metric?",choices:["It replaces dx","It is the same thing as v<sub>s</sub>","It appears only in the Euclidean metric","It does not appear directly; it is computed from the metric"],answer:3,feedback:"This is the key move. &theta; is derived from the metric; it measures whether nearby volumes expand or contract."},{focus:"meaning of theta",question:"What does a negative &theta; mean ahead of the bubble?",choices:["Space is expanding there","Space is contracting there","The ship is locally faster than light","The metric has become Euclidean again"],answer:1,feedback:"Correct. Negative &theta; means contraction. Positive &theta; means expansion. That is why &theta; is so useful to graph."}],captions:e,defaultCaption:e["flat spatial distance"],progress:"#progress",score:"#score",focus:"#focusStrip",question:"#question",answers:"#answers",feedback:"#feedback",next:"#nextButton",restart:"#restartButton",caption:"#equationCaption",completeFocus:"Metric lesson complete",verdicts:{perfect:"Perfect. You can now distinguish the ruler, the spacetime metric, the warp term, and &theta;.",strong:"Strong pass. The geometry is mostly behaving in your head now.",partial:"Good foothold. Review the difference between the metric itself and quantities derived from it.",early:"Early orbit. Start again and watch for the Euclidean-vs-spacetime distinction."}}),i({questions:[{focus:"field equations",question:"What do Einstein's field equations connect?",choices:["Velocity and fuel efficiency","Spacetime geometry and stress-energy","Euclidean distance and ordinary mass only","The ship's engine power and dashboard speed"],answer:1,feedback:"Yes. In compact form, G<sub>&mu;&nu;</sub> = 8&pi;T<sub>&mu;&nu;</sub>: geometry is related to the stress-energy content."},{focus:"metric as a solution",question:"What does it mean to say the warp drive metric is a solution to Einstein's equations?",choices:["The ship has a known buildable engine","The metric ignores gravity entirely","The metric has a matching stress-energy tensor that would source it","It proves faster-than-light travel is easy"],answer:2,feedback:"Right. A metric is a geometry. If its curvature corresponds to some T<sub>&mu;&nu;</sub>, then mathematically it solves the equations."},{focus:"10c bubble source",question:"Can the equations describe a warp bubble with v<sub>s</sub> = 10c?",choices:["No, because no coordinate speed can ever exceed c","Only if the ship itself locally moves at 10c","Only if &theta; is set to zero everywhere","Yes, if the required T<sub>&mu;&nu;</sub> can be provided"],answer:3,feedback:"Exactly. The field equations do not reject a 10c bubble speed by itself; they demand the specific T<sub>&mu;&nu;</sub> that would source that geometry. The hard part is whether such stress-energy can physically exist."},{focus:"metric first",question:"In the Alcubierre construction, what is usually chosen first?",choices:["A normal fuel tank","The desired warp metric","A pre-existing starship engine","A Euclidean map with no time coordinate"],answer:1,feedback:"Exactly. Alcubierre starts with a desired spacetime geometry, then uses the field equations to infer the required stress-energy."},{focus:"stress-energy tensor",question:"What role does T<sub>&mu;&nu;</sub> play?",choices:["It is the ship's local speedometer","It is another name for &theta;","It describes the matter, energy, pressure, and stresses required by the geometry","It removes the need for curvature"],answer:2,feedback:"Correct. T<sub>&mu;&nu;</sub> is the stress-energy tensor: the source side of the field equations."},{focus:"exotic requirement",question:"What is the catch with the stress-energy tensor for the Alcubierre metric?",choices:["It only requires ordinary dust","It contains no energy at all","It is automatically easy to manufacture","It requires negative energy density in the bubble wall"],answer:3,feedback:"There it is: the geometry is mathematically allowed, but the required source includes exotic negative energy density."},{focus:"superluminal v_s",question:"Why can v<sub>s</sub> exceed c in the metric without the ship locally outrunning light?",choices:["The speed of light stops applying inside the bubble","v<sub>s</sub> is the coordinate speed of the bubble, while local motion inside can remain subluminal","The ship becomes massless","&theta; cancels special relativity"],answer:1,feedback:"Exactly. Relativity limits local motion through nearby spacetime. The bubble's coordinate displacement relative to far-away observers is a different thing."},{focus:"carried by the bubble",question:"Why is the ship described as being carried along by the bubble?",choices:["The ship pushes against an invisible wall","The ship constantly accelerates faster than light","The bubble's geometry moves the local region containing the ship","The Euclidean metric drags it forward"],answer:2,feedback:"Yes. The ship sits in a locally calm interior while the surrounding geometry changes how that interior relates to distant space."},{focus:"geodesics",question:"What does geodesic motion mean for the ship inside the bubble?",choices:["It must fire rockets at infinite thrust","It stops being affected by spacetime","It travels through space faster than nearby light beams","It can follow a natural free-fall path locally, without feeling huge acceleration"],answer:3,feedback:"Right. A geodesic is the natural path through spacetime. The craft can coast locally while the bubble geometry does the dramatic global work."}],captions:s,defaultCaption:s["field equations"],progress:"#fieldProgress",score:"#fieldScore",focus:"#fieldFocus",question:"#fieldQuestion",answers:"#fieldAnswers",feedback:"#fieldFeedback",next:"#fieldNextButton",restart:"#fieldRestartButton",caption:"#fieldCaption",completeFocus:"Field-equations lesson complete",verdicts:{perfect:"Perfect. You have the core logic: choose a metric, infer T<sub>&mu;&nu;</sub>, respect local c, ride the geodesic.",strong:"Strong pass. You have the mathematical permission slip and the physical catch separated.",partial:"Good foothold. Revisit the difference between coordinate bubble speed and local ship speed.",early:"Start again from G<sub>&mu;&nu;</sub> = 8&pi;T<sub>&mu;&nu;</sub>: geometry and source have to match."}}),i({questions:[{focus:"why special",question:"Why is the Alcubierre metric special?",choices:["It describes a moving warp bubble whose coordinate speed v<sub>s</sub> can exceed c","It removes the need for Einstein's equations","It makes the ship locally outrun nearby light","It is just the Euclidean metric with a new name"],answer:0,feedback:"Yes. The special feature is the moving bubble geometry: v<sub>s</sub> is a coordinate speed that can exceed c while local motion can remain ordinary."},{focus:"shape function",question:"What does f(r<sub>s</sub>) do in the warp metric?",choices:["It is the ship's clock","It sets the bubble profile: near 1 inside, near 0 outside, changing in the wall","It is the speed limit c","It replaces the stress-energy tensor"],answer:1,feedback:"Exactly. f(r<sub>s</sub>) shapes the bubble and makes the wall the transition region where the geometry changes."},{focus:"wall structure",question:"Where does the important nontrivial structure of the Alcubierre source live?",choices:["Uniformly everywhere in the universe","Only at the ship's nose","Mainly in the bubble wall, where f(r<sub>s</sub>) changes","Only in empty Euclidean space"],answer:2,feedback:"Right. The wall is where the shape function changes, so that is where the source and curvature structure become physically important."},{focus:"theta meaning",question:"What is &theta; measuring in the visualization?",choices:["Whether nearby spatial volume elements expand or contract","The ship's fuel efficiency","The value of c","The total mass of the spacecraft"],answer:0,feedback:"Correct. &theta; is an expansion scalar: it tracks local expansion or contraction of nearby spatial volume elements."},{focus:"superluminal coordinate speed",question:"Why can v<sub>s</sub> &gt; c without directly violating special relativity?",choices:["Because special relativity stops applying inside any spacecraft","Because light slows down inside the bubble","Because &theta; cancels c","Because v<sub>s</sub> is the bubble's coordinate speed, not the ship's local speed through nearby spacetime"],answer:3,feedback:"Exactly. Relativity constrains local motion through nearby spacetime. The bubble's coordinate displacement relative to distant observers is different."},{focus:"einstein equations",question:"After choosing the Alcubierre metric, what do Einstein's equations tell us?",choices:["What stress-energy tensor T<sub>&mu;&nu;</sub> would be required to source that geometry","How to build the engine with ordinary fuel","That no source is needed","That the metric must become Euclidean"],answer:0,feedback:"Yes. Compute the geometry side G<sub>&mu;&nu;</sub>, then infer the required source T<sub>&mu;&nu;</sub>."},{focus:"tensor field",question:"What does T<sub>&mu;&nu;</sub>(t, x, y, z) mean?",choices:["One single number attached to the whole bubble","A tensor field assigning stress-energy information to each spacetime event","The distance from the ship","The expansion scalar &theta;"],answer:1,feedback:"Right. T<sub>&mu;&nu;</sub> is a spacetime-dependent tensor field, not one global value."},{focus:"physical catch",question:"What is the major physical catch for the Alcubierre source?",choices:["It requires no curvature","It only works if time is removed","It requires exotic stress-energy, including negative energy density","It only changes the y direction"],answer:2,feedback:"Correct. The mathematical geometry is one thing; the required exotic stress-energy is the hard physical issue."},{focus:"ship carried along",question:"How is the ship carried along by the bubble?",choices:["The ship can follow a geodesic in the locally calm interior while the bubble geometry changes its relation to distant space","The ship locally accelerates faster than light","The ship exits spacetime","The Euclidean metric drags the ship forward"],answer:0,feedback:"Yes. The ship can coast locally along a geodesic inside the bubble while the global geometry does the dramatic work."},{focus:"big caveat",question:"What is the big caveat of the Alcubierre drive idea?",choices:["A mathematical solution does not mean we know a physically buildable engineering method","The metric has no relation to Einstein's equations","The bubble wall has no source","The ship must locally move faster than light"],answer:0,feedback:"Exactly. The metric is a serious mathematical solution, but that is not the same as known engineering feasibility."}],captions:t,defaultCaption:t["why special"],progress:"#finalProgress",score:"#finalScore",focus:"#finalFocus",question:"#finalQuestion",answers:"#finalAnswers",feedback:"#finalFeedback",next:"#finalNextButton",restart:"#finalRestartButton",caption:"#finalCaption",completeFocus:"Chapter 1 checkpoint complete",showVerdict:!1,verdicts:{perfect:"",strong:"",partial:"",early:""}})}();